const files = items.map(i => i.json).filter(f => !f.trashed && !f.shared);
const report = [];

// Basic duplicate detection
const hashCount = {};
const nameSizeCount = {};

for (const f of files) {
  const nameNorm = String(f.name || '').toLowerCase().trim();
  const size = f.size || 0;
  const keyNameSize = `${nameNorm}_${size}`;
  const keyHash = f.md5Checksum;

  if (keyHash) {
    hashCount[keyHash] = (hashCount[keyHash] || 0) + 1;
  }
  nameSizeCount[keyNameSize] = (nameSizeCount[keyNameSize] || 0) + 1;
}

for (const f of files) {
  const nameNorm = String(f.name || '').toLowerCase().trim();
  const size = f.size || 0;
  const keyNameSize = `${nameNorm}_${size}`;
  const keyHash = f.md5Checksum;

  let dupScore = 'baixo';
  if (keyHash && hashCount[keyHash] > 1) {
    dupScore = 'idêntico provável';
  } else if (nameSizeCount[keyNameSize] > 1) {
    dupScore = 'alto';
  }

  let acao = 'nenhuma ação executada';
  let sugestao_nome = f.name;

  if (nameNorm.includes('whatsapp') && nameNorm.includes('image')) {
    sugestao_nome = `WPP_IMG_${f.createdTime.split('T')[0]}.jpg`;
    acao = 'sugestão de renomeação';
  }

  report.push({
    file_id: f.id,
    caminho: f.parents ? f.parents.join(',') : 'root',
    tamanho: size,
    data: f.createdTime,
    hash: keyHash || 'N/A',
    possivel_duplicado: dupScore !== 'baixo',
    nivel_confianca_duplicidade: dupScore,
    sugestao_de_nome: sugestao_nome,
    acao_recomendada: acao
  });
}

return [{ json: { arquivos_analisados: files.length, relatorio_detalhado: report } }];

